function getFrameCapacity(material, height, columnName) {
  var mat = window.FRAME_CAPACITY[material];
  if (!mat) return null;
  var h = mat[height];
  if (!h) return null;
  return h[columnName] ? h[columnName].capacity : null;
}

function getFrameColumnNames(material) {
  var mat = window.FRAME_CAPACITY[material];
  if (!mat) return [];
  var h = mat[Object.keys(mat)[0]];
  return Object.keys(h);
}